t.script:
                let cart = [];
                let currentOpnameId = null;

                // Tab Switching
                document.querySelectorAll('.tab').forEach(tab => {
                    tab.addEventListener('click', () => {
                        document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
                        tab.classList.add('active');

                        const target = tab.dataset.tab;
                        document.getElementById('stock-in-view').classList.add('hidden');
                        document.getElementById('opname-view').classList.add('hidden');
                        document.getElementById('master-data-view').classList.add('hidden');

                        document.getElementById(target + '-view').classList.remove('hidden');
                    });
                });

                // Stock In Logic
                document.getElementById('add-item-btn').addEventListener('click', () => {
                    const select = document.getElementById('material-select');
                    const qtyInput = document.getElementById('input-qty');
                    const priceInput = document.getElementById('input-price');

                    if (!select.value || !qtyInput.value) return;

                    const option = select.options[select.selectedIndex];
                    const item = {
                        product_id: parseInt(select.value),
                        name: option.dataset.name,
                        uom: option.dataset.uom,
                        quantity: parseFloat(qtyInput.value),
                        price: parseFloat(priceInput.value || 0)
                    };

                    cart.push(item);
                    renderCart();

                    // Reset
                    select.value = "";
                    qtyInput.value = "";
                    priceInput.value = "";
                });

                function renderCart() {
                    const container = document.getElementById('cart-items');
                    const saveBtn = document.getElementById('save-container');

                    container.innerHTML = '';
                    cart.forEach((item, index) => {
                        const div = document.createElement('div');
                        div.className = 'item-card';
                        div.innerHTML = `



${item.name}

${item.quantity} ${item.uom} — Rp ${item.price.toLocaleString()}


                        `;
                        container.appendChild(div);
                    });

                    if (cart.length > 0) {
                        saveBtn.classList.remove('hidden');
                    } else {
                        saveBtn.classList.add('hidden');
                    }
                }

                function removeItem(index) {
                    cart.splice(index, 1);
                    renderCart();
                }

                document.getElementById('save-stock-btn').addEventListener('click', async () => {
                    const btn = document.getElementById('save-stock-btn');
                    btn.disabled = true;
                    btn.innerText = 'MEMPROSES...';

                    try {
                        const response = await fetch('/api/purecf/stock/incoming', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                                jsonrpc: "2.0",
                                params: { items: cart }
                            })
                        });
                        const result = await response.json();
                        if (result.result && result.result.status === 'success') {
                            alert('Stok Berhasil Disimpan');
                            cart = [];
                            renderCart();
                            location.reload();
                        } else {
                            alert('Gagal menyimpan stok: ' + (result.error ? result.error.message : 'Unknown error'));
                        }
                    } catch (e) {
                        alert('Error: ' + e.message);
                    } finally {
                        btn.disabled = false;
                        btn.innerText = 'SIMPAN & KIRIM KE ODOO';
                    }
                });

                // Opname Logic
                function openOpnameDialog(id, name, uom) {
                    currentOpnameId = id;
                    document.getElementById('dialog-title').innerText = 'Opname: ' + name;
                    document.getElementById('dialog-uom').innerText = uom;
                    document.getElementById('dialog-qty').value = '';
                    document.getElementById('opname-dialog').classList.remove('hidden');
                    document.getElementById('opname-dialog').style.display = 'flex';
                }

                function closeDialog() {
                    document.getElementById('opname-dialog').classList.add('hidden');
                    document.getElementById('opname-dialog').style.display = 'none';
                }

                document.getElementById('confirm-opname-btn').addEventListener('click', async () => {
                    const qty = document.getElementById('dialog-qty').value;
                    if (qty === '') return;

                    const btn = document.getElementById('confirm-opname-btn');
                    btn.disabled = true;

                    try {
                        const response = await fetch('/api/purecf/update_stock', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                                jsonrpc: "2.0",
                                params: { 
                                    product_id: currentOpnameId,
                                    new_quantity: parseFloat(qty)
                                }
                            })
                        });
                        const result = await response.json();
                        if (result.result && result.result.status === 'success') {
                            closeDialog();
                            location.reload();
                        } else {
                            alert('Gagal update stok: ' + (result.result ? result.result.message : 'Error'));
                        }
                    } catch (e) {
                        alert('Error: ' + e.message);
                    } finally {
                        btn.disabled = false;
                    }
                });

                // Search Logic
                document.getElementById('opname-search').addEventListener('input', (e) => {
                    const query = e.target.value.toLowerCase();
                    document.querySelectorAll('#opname-list .opname-card').forEach(card => {
                        const name = card.dataset.name;
                        if (name.includes(query)) {
                            card.classList.remove('hidden');
                        } else {
                            card.classList.add('hidden');
                        }
                    });
                });

                document.getElementById('master-search').addEventListener('input', (e) => {
                    filterMaster();
                });

                document.querySelectorAll('.chip').forEach(chip => {
                    chip.addEventListener('click', () => {
                        document.querySelectorAll('.chip').forEach(c => c.classList.remove('active'));
                        chip.classList.add('active');
                        filterMaster();
                    });
                });

                function filterMaster() {
                    const query = document.getElementById('master-search').value.toLowerCase();
                    const activeFilter = document.querySelector('.chip.active').dataset.filter;

                    document.querySelectorAll('#master-list .master-item').forEach(card => {
                        const name = card.dataset.name;
                        const status = card.dataset.status;

                        const matchesSearch = name.includes(query);
                        const matchesFilter = activeFilter === 'all' || status === activeFilter;

                        if (matchesSearch && matchesFilter) {
                            card.classList.remove('hidden');
                        } else {
                            card.classList.add('hidden');
                        }
                    });
                }

                // Edit Min Qty
                function editMinQty(id, current) {
                    const newVal = prompt('Input Stok Minimum Baru:', current);
                    if (newVal !== null) {
                        updateMinQty(id, parseFloat(newVal));
                    }
                }

                async function updateMinQty(id, val) {
                    try {
                        const response = await fetch('/jsonrpc', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                                jsonrpc: "2.0",
                                method: "call",
                                params: {
                                    model: "product.template",
                                    method: "write",
                                    args: [[id], { x_min_qty: val }],
                                    kwargs: {}
                                }
                            })
                        });
                        location.reload();
                    } catch (e) {
                        alert('Error updating min qty');
                    }
                }
